   481→  /** LINE 관절 이동 (QueueTag + 좌표 폴링으로 도착 확인) */
   482→  async moveLineJ(joints: number[], speed: number, acc: number): Promise<TmsctResponse> {
   483→    const jointStr = joints.map(j => j.toFixed(4)).join(',');
   484→    return this.sendMotionScript(`Line("JPP",${jointStr},${speed},${acc},0,false)`, joints);
   485→  }
   486→
   487→  /** LINE 직교 이동 (QueueTag + 좌표 폴링) */
