   497→
   498→  /** IO 상태 조회 (TMSVR) */
   499→  async getIO(): Promise<TmsvrResponse> {
   500→    // Ctrl_DO, Ctrl_DI, Ctrl_AO, Ctrl_AI 항목 조회
