    17→  server.tool(
    18→    'tm_connect',
    19→    '로봇 연결 (TMSCT 5890 + TMSVR 5891)',
    20→    {
    21→      host: z.string().describe('로봇 IP 주소'),
    22→      sctPort: z.number().optional().describe('TMSCT 포트 (기본 5890)'),
    23→      svrPort: z.number().optional().describe('TMSVR 포트 (기본 5891)'),
    24→    },
    25→    async ({ host, sctPort, svrPort }) => {
    26→      const result = await client.connect(host, sctPort, svrPort);
    27→      return { content: [{ type: 'text' as const, text: result }] };
    28→    }
    29→  );
    30→
    31→  server.tool(
    32→    'tm_disconnect',
    33→    '로봇 연결 해제',
    34→    {},
    35→    async () => {
    36→      const result = client.disconnect();
    37→      return { content: [{ type: 'text' as const, text: result }] };
    38→    }
    39→  );
    40→
    41→  server.tool(
    42→    'tm_status',
    43→    '연결 상태 + 로봇 상태 조회',
    44→    {},
    45→    async () => {
    46→      const info = client.getStatus();
    47→      let text = `호스트: ${info.host || '(미연결)'}\n`;
    48→      text += `TMSCT(${info.sctPort}): ${info.sctConnected ? '연결됨' : '미연결'}\n`;
    49→      text += `TMSVR(${info.svrPort}): ${info.svrConnected ? '연결됨' : '미연결'}`;
    50→
    51→      // TMSVR 연결되어 있으면 로봇 상태도 조회
    52→      if (info.svrConnected) {
    53→        try {
    54→          const pos = await client.getPosition();
    55→          text += `\n\n[로봇 위치]\n${pos.data}`;
    56→        } catch {
    57→          text += '\n\n로봇 위치 조회 실패';
    58→        }
    59→      }
    60→
    61→      return { content: [{ type: 'text' as const, text }] };
    62→    }
    63→  );
    64→
    65→  // ===== 실행 제어 =====
    66→
    67→  server.tool(
    68→    'tm_pause',
    69→    '로봇 일시정지',
    70→    {},
    71→    async () => {
    72→      const res = await client.pause();
